export enum SubmissionStatus {
  COMPLETED = 'Completed',
  FAILED = 'Failed',
  PENDING = 'Pending'
}

export interface TestCase {
  input: string;
  expectedOutput: string;
}

export interface Problem {
  id: string;
  title: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  description: string;
