  id: string;
  userId: string;
  problemId: string;
  language: string;
  status: SubmissionStatus;
  marks: number;
  code: string;
  timestamp: string;
}

export interface DailyStats {
  totalTasks: number;
  completedTasks: number;
  remainingTasks: number;
  marks: number;
  productivity: number;
}

