export const MOCK_ADMINS: User[] = [
  { id: 'a1', name: 'System Admin', email: 'admin@gmail.com', role: UserRole.ADMIN, category: PerformanceCategory.EXCELLENT }
];

// Generate 120 mock students
export const MOCK_STUDENTS: User[] = Array.from({ length: 120 }, (_, i) => ({
  id: `s${i + 1}`,
  name: `Student ${i + 1}`,
  email: `student${i + 1}@gmail.com`,
  role: UserRole.USER,
  category: i % 3 === 0 ? PerformanceCategory.EXCELLENT : (i % 2 === 0 ? PerformanceCategory.MEDIUM : PerformanceCategory.LOW)
