interface CodeEditorProps {
  problem: Problem;
  onClose: () => void;
  onSubmit: (status: SubmissionStatus, code: string, marks: number) => void;
}

export const CodeEditor: React.FC<CodeEditorProps> = ({ problem, onClose, onSubmit }) => {
  const [language, setLanguage] = useState('python');
  const [code, setCode] = useState('');
  const [isEvaluating, setIsEvaluating] = useState(false);
  const [testResult, setTestResult] = useState<{success: boolean, message: string} | null>(null);

  const handleSimulateSubmit = () => {
    setIsEvaluating(true);
    setTestResult(null);

    // Simulate compilation delay
    setTimeout(() => {
      const isCorrect = code.length > 20; // Mock check: if code is longer than 20 chars, assume it works for demo
      if (isCorrect) {
        setTestResult({ success: true, message: 'All test cases passed! (3/3)' });
        setTimeout(() => {
          onSubmit(SubmissionStatus.COMPLETED, code, 10);
        }, 1500);
      } else {
        setTestResult({ success: false, message: 'Failed at Test Case 1: Expected "olleh", got ""' });
        setIsEvaluating(false);
      }
    }, 2000);
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl w-full max-w-5xl h-[90vh] flex flex-col shadow-2xl overflow-hidden">
        {/* Header */}
        <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between">
          <div>
            <h2 className="text-xl font-bold text-slate-900">{problem.title}</h2>
            <p className="text-sm text-slate-500">Difficulty: {problem.difficulty}</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
          </button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Left: Problem Statement */}
          <div className="w-1/3 p-6 border-r border-slate-100 overflow-y-auto bg-slate-50/50">
            <h3 className="font-semibold text-slate-900 mb-3">Problem Description</h3>
            <p className="text-sm text-slate-700 leading-relaxed mb-6">{problem.description}</p>

            <h3 className="font-semibold text-slate-900 mb-2">Test Cases</h3>
            <div className="space-y-3">
              {problem.testCases.map((tc, idx) => (
                <div key={idx} className="bg-white p-3 rounded-lg border border-slate-200 text-xs font-mono">
                  <div className="text-slate-400 mb-1">Input: <span className="text-slate-900">{tc.input}</span></div>
                  <div className="text-slate-400">Output: <span className="text-indigo-600">{tc.expectedOutput}</span></div>
                </div>
              ))}
            </div>
          </div>

          {/* Right: Editor */}
          <div className="flex-1 flex flex-col bg-slate-900">
            <div className="p-3 bg-slate-800 flex items-center justify-between">
              <select 
                value={language} 
                onChange={(e) => setLanguage(e.target.value)}
                className="bg-slate-700 text-slate-200 text-xs px-2 py-1 rounded border border-slate-600 outline-none"
              >
                <option value="python">Python 3</option>
                <option value="java">Java</option>
                <option value="cpp">C++</option>
              </select>
            </div>

            <textarea
              className="flex-1 bg-slate-900 text-indigo-400 font-mono p-6 resize-none outline-none text-sm placeholder:text-slate-700"
              placeholder="# Write your solution here..."
              value={code}
              onChange={(e) => setCode(e.target.value)}
            />

            {/* Evaluation Console */}
            {testResult && (
              <div className={`p-4 border-t ${testResult.success ? 'bg-emerald-900/20 border-emerald-800' : 'bg-red-900/20 border-red-800'}`}>
                <p className={`text-sm font-medium ${testResult.success ? 'text-emerald-400' : 'text-red-400'}`}>
                  {testResult.message}
                </p>
              </div>
            )}

            <div className="p-4 bg-slate-800 flex items-center justify-end gap-3">
              <Button variant="ghost" onClick={onClose} className="text-slate-400 hover:text-white border-slate-700">
                Cancel
              </Button>
              <Button 
                onClick={handleSimulateSubmit} 
                disabled={isEvaluating || !code.trim()}
                className="min-w-[120px]"
              >
                {isEvaluating ? (
                  <span className="flex items-center gap-2">
                    <svg className="animate-spin h-4 w-4 text-white" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Evaluating...
                  </span>
                ) : 'Run & Submit'}
              </Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

