// --- USER VIEW ---
const UserDashboard: React.FC<{ user: User }> = ({ user }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [activeProblem, setActiveProblem] = useState<Problem | null>(null);
  const [showReminder, setShowReminder] = useState(false);

  useEffect(() => {
    const subs = getSubmissions().filter(s => s.userId === user.id);
    setSubmissions(subs);

    // Smart Reminder
    const incomplete = subs.length < APP_CONFIG.DAILY_TASK_COUNT;
    if (incomplete) {
      setTimeout(() => setShowReminder(true), 1500);
    }
  }, [user.id]);

  const stats: DailyStats = {
    totalTasks: APP_CONFIG.DAILY_TASK_COUNT,
    completedTasks: submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length,
    remainingTasks: APP_CONFIG.DAILY_TASK_COUNT - submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length,
    marks: submissions.reduce((sum, s) => sum + s.marks, 0),
    productivity: (submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length / APP_CONFIG.DAILY_TASK_COUNT) * 100
  };

  const handleSolveSubmit = (status: SubmissionStatus, code: string, marks: number) => {
    if (!activeProblem) return;
    const newSub: Submission = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      problemId: activeProblem.id,
      language: 'python',
      status,
      marks,
      code,
      timestamp: new Date().toISOString()
    };
    addSubmission(newSub);
    setSubmissions(prev => {
        const existing = prev.findIndex(s => s.problemId === activeProblem.id);
        if (existing > -1) {
            const updated = [...prev];
            updated[existing] = newSub;
            return updated;
        }
        return [...prev, newSub];
    });
    setActiveProblem(null);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6">
      {/* Header Info */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="col-span-1 md:col-span-2 space-y-4">
          <h2 className="text-3xl font-bold text-slate-900">Hello, {user.name.split(' ')[0]}! 👋</h2>
          <p className="text-slate-500">You have {stats.remainingTasks} coding challenges left for today.</p>
        </div>
        <div className="flex justify-end items-start">
          <CountdownTimer />
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {[
          { label: 'Progress', value: `${stats.completedTasks}/${stats.totalTasks}`, color: 'bg-indigo-50 text-indigo-700', icon: '🎯' },
          { label: 'Today\'s Marks', value: `${stats.marks}/50`, color: 'bg-emerald-50 text-emerald-700', icon: '⭐' },
          { label: 'Productivity', value: `${stats.productivity}%`, color: 'bg-amber-50 text-amber-700', icon: '📈' },
          { label: 'Category', value: user.category, color: 'bg-purple-50 text-purple-700', icon: '🏆' },
        ].map((item, idx) => (
          <div key={idx} className={`${item.color} p-6 rounded-2xl border border-current opacity-20 border-opacity-10 shadow-sm relative overflow-hidden group`}>
            <div className="relative z-10">
              <span className="text-2xl mb-2 block">{item.icon}</span>
              <p className="text-xs uppercase tracking-wider font-bold opacity-70">{item.label}</p>
              <h3 className="text-2xl font-bold mt-1">{item.value}</h3>
            </div>
          </div>
        ))}
      </div>

      {/* Progress Bar */}
      <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm mb-8">
        <div className="flex items-center justify-between mb-2">
          <span className="text-sm font-semibold text-slate-700">Completion Status</span>
          <span className="text-sm font-bold text-indigo-600">{stats.productivity}%</span>
        </div>
        <div className="w-full h-3 bg-slate-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-indigo-600 rounded-full transition-all duration-1000 ease-out"
            style={{ width: `${stats.productivity}%` }}
          ></div>
        </div>
      </div>

      {/* Task List */}
      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-50 flex items-center justify-between">
          <h3 className="font-bold text-slate-900">Today's Tasks</h3>
          <span className="text-xs text-slate-400 font-mono">DATE: {new Date().toLocaleDateString()}</span>
        </div>
        <div className="divide-y divide-slate-50">
          {PROBLEMS.map((problem, index) => {
            const sub = submissions.find(s => s.problemId === problem.id);
            const isCompleted = sub?.status === SubmissionStatus.COMPLETED;

            return (
              <div key={problem.id} className="p-6 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-6">
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold ${isCompleted ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
                    {index + 1}
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-900">{problem.title}</h4>
                    <p className="text-sm text-slate-500 line-clamp-1 max-w-md">{problem.description}</p>
                    <div className="flex items-center gap-3 mt-2">
                      <span className={`px-2 py-0.5 rounded-md text-[10px] font-bold uppercase tracking-wider ${
                        problem.difficulty === 'Easy' ? 'bg-emerald-50 text-emerald-600' :
                        problem.difficulty === 'Medium' ? 'bg-amber-50 text-amber-600' : 'bg-red-50 text-red-600'
                      }`}>
                        {problem.difficulty}
                      </span>
                      <span className="text-slate-300">•</span>
                      <span className="text-xs text-slate-400">{isCompleted ? '10/10 Marks' : '10 Marks available'}</span>
                    </div>
                  </div>
                </div>
                <div>
                  {isCompleted ? (
                    <div className="flex items-center gap-2 text-emerald-600 font-bold">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                      Completed
                    </div>
                  ) : (
                    <Button onClick={() => setActiveProblem(problem)}>Solve Challenge</Button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Reminder Popup */}
      {showReminder && (
        <div className="fixed bottom-6 right-6 z-[200] animate-bounce-in">
          <div className="bg-white rounded-2xl shadow-2xl border border-indigo-100 p-6 max-w-sm flex gap-4">
            <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center text-2xl flex-shrink-0">
              🚀
            </div>
            <div>
              <h4 className="font-bold text-slate-900">Complete your task!</h4>
              <p className="text-sm text-slate-500 mt-1">Deadline is approaching. Finish your 5 coding challenges now!</p>
              <Button size="sm" className="mt-4" onClick={() => setShowReminder(false)}>Got it</Button>
            </div>
          </div>
        </div>
      )}

      {/* Editor Modal */}
      {activeProblem && (
        <CodeEditor 
          problem={activeProblem} 
          onClose={() => setActiveProblem(null)}
          onSubmit={handleSolveSubmit}
        />
      )}
    </div>
  );
};

