const UserDashboard: React.FC<{ user: User }> = ({ user }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [activeProblem, setActiveProblem] = useState<Problem | null>(null);
  const [encouragement, setEncouragement] = useState<{show: boolean, msg: string, emoji: string}>({show: false, msg: '', emoji: ''});

  useEffect(() => {
    setSubmissions(getSubmissions().filter(s => s.userId === user.id));
  }, [user.id]);

  const stats: DailyStats = {
    totalTasks: APP_CONFIG.DAILY_TASK_COUNT,
    completedTasks: submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length,
    remainingTasks: APP_CONFIG.DAILY_TASK_COUNT - submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length,
    marks: submissions.reduce((sum, s) => sum + s.marks, 0),
    productivity: (submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length / APP_CONFIG.DAILY_TASK_COUNT) * 100
  };

  const handleSolveSubmit = (status: SubmissionStatus, code: string, marks: number) => {
    if (!activeProblem) return;
    const newSub: Submission = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      problemId: activeProblem.id,
      language: 'python',
      status,
      marks,
      code,
      timestamp: new Date().toISOString()
    };
    addSubmission(newSub);
    setSubmissions(prev => [...prev, newSub]);
    setActiveProblem(null);

    // Trigger encouragement
    const nextCompletedCount = stats.completedTasks + 1;
    let msg = "Good Job!";
    let emoji = "👍";

    if (nextCompletedCount === 1) { msg = "Good!"; emoji = "✨"; }
    else if (nextCompletedCount === 2) { msg = "Very Good!"; emoji = "🔥"; }
    else if (nextCompletedCount === 3) { msg = "Excellent Work!"; emoji = "🌟"; }
    else if (nextCompletedCount === 4) { msg = "Fantablouse!"; emoji = "🚀"; }
    else if (nextCompletedCount === 5) { msg = "Incredible! Task Completed! Rockstar!"; emoji = "🏆"; }

    setEncouragement({ show: true, msg, emoji });
    setTimeout(() => setEncouragement(prev => ({ ...prev, show: false })), 3000);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6">
      {/* Encouragement Popup Overlay */}
      {encouragement.show && (
        <div className="fixed inset-0 flex items-center justify-center z-[300] pointer-events-none">
          <div className="bg-white/90 backdrop-blur-xl border border-indigo-100 shadow-[0_32px_64px_-16px_rgba(0,0,0,0.2)] p-10 rounded-[3rem] text-center animate-bounce-in flex flex-col items-center">
            <span className="text-8xl mb-6">{encouragement.emoji}</span>
            <h3 className="text-4xl font-black text-slate-900 mb-2 uppercase tracking-tighter">{encouragement.msg}</h3>
            <p className="text-indigo-600 font-bold text-lg">Daily Progress: {stats.completedTasks + 1}/5</p>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-12">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Daily Modules</h2>
          <p className="text-slate-500 font-medium text-lg">Ready to level up, {user.name.split(' ')[0]}?</p>
        </div>
        <CountdownTimer />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 mb-12">
        {[
          { label: 'Completion', value: `${stats.completedTasks}/5`, color: 'bg-indigo-600', icon: '🎯' },
          { label: 'Marks Earned', value: `${stats.marks}/50`, color: 'bg-emerald-600', icon: '⚡' },
          { label: 'Productivity', value: `${stats.productivity}%`, color: 'bg-amber-500', icon: '📈' },
          { label: 'Global Rank', value: user.category, color: 'bg-purple-600', icon: '👑' },
        ].map((item, idx) => (
          <div key={idx} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-6">
            <div className={`w-14 h-14 rounded-2xl ${item.color} flex items-center justify-center text-2xl shadow-lg`}>
              {item.icon}
            </div>
            <div>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{item.label}</p>
              <h4 className="text-2xl font-bold text-slate-900">{item.value}</h4>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 gap-6">
        {PROBLEMS.map((problem, index) => {
          const sub = submissions.find(s => s.problemId === problem.id);
          const isCompleted = sub?.status === SubmissionStatus.COMPLETED;

          return (
            <div key={problem.id} className={`group bg-white rounded-3xl p-1 transition-all duration-300 ${isCompleted ? 'border-emerald-100' : 'hover:shadow-xl hover:-translate-y-1'}`}>
               <div className={`p-6 sm:p-8 rounded-[1.4rem] border border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-6 ${isCompleted ? 'bg-emerald-50/30' : 'bg-white'}`}>
                  <div className="flex items-center gap-8 flex-1">
                     <div className={`w-16 h-16 rounded-2xl flex items-center justify-center font-black text-2xl shadow-inner ${isCompleted ? 'bg-emerald-500 text-white' : 'bg-slate-50 text-slate-300'}`}>
                        {index + 1}
                     </div>
                     <div className="flex-1">
                        <p className="text-xs font-bold text-indigo-500 uppercase tracking-widest mb-1">Module {index + 1}</p>
                        <h4 className="text-2xl font-bold text-slate-900 mb-2">{problem.title}</h4>
