                           <span className="text-sm text-slate-500 font-medium">Difficulty: <span className={problem.difficulty === 'Easy' ? 'text-emerald-500' : problem.difficulty === 'Medium' ? 'text-amber-500' : 'text-red-500'}>{problem.difficulty}</span></span>
                           <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                           <span className="text-sm text-slate-500 font-medium">Value: 10 Marks</span>
