                       <Button size="lg" className="w-full sm:w-auto px-10 rounded-2xl" onClick={() => setActiveProblem(problem)}>Start Coding</Button>
                     )}
                  </div>
               </div>
            </div>
          );
        })}
      </div>

      {activeProblem && (
        <CodeEditor 
          problem={activeProblem} 
