const DB_KEYS = {
  USERS: 'ai_system_users',
  SUBMISSIONS: 'ai_system_submissions',
  CURRENT_USER: 'ai_system_current_user'
};

export const initDb = () => {
  if (!localStorage.getItem(DB_KEYS.USERS)) {
    const allUsers = [...MOCK_ADMINS, ...MOCK_STUDENTS];
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(allUsers));
  }
  if (!localStorage.getItem(DB_KEYS.SUBMISSIONS)) {
    localStorage.setItem(DB_KEYS.SUBMISSIONS, JSON.stringify([]));
  }
};

export const getUsers = (): User[] => {
  return JSON.parse(localStorage.getItem(DB_KEYS.USERS) || '[]');
};

export const getSubmissions = (): Submission[] => {
  return JSON.parse(localStorage.getItem(DB_KEYS.SUBMISSIONS) || '[]');
};

export const incrementAccess = (userId: string): boolean => {
  const users = getUsers();
  const userIndex = users.findIndex(u => u.id === userId);
  if (userIndex === -1) return false;

  const today = new Date().toDateString();
  const user = users[userIndex];

  // Reset if date changed
  if (user.lastAccessDate !== today) {
    user.accessCount = 1;
    user.lastAccessDate = today;
  } else {
    if (user.accessCount >= APP_CONFIG.MAX_DAILY_ACCESS) return false;
    user.accessCount += 1;
  }

  localStorage.setItem(DB_KEYS.USERS, JSON.stringify(users));
  localStorage.setItem(DB_KEYS.CURRENT_USER, JSON.stringify(user));
  return true;
};

export const addSubmission = (submission: Submission) => {
  const current = getSubmissions();
  const existingIndex = current.findIndex(s => s.userId === submission.userId && s.problemId === submission.problemId);
  if (existingIndex > -1) {
    current[existingIndex] = submission;
  } else {
    current.push(submission);
  }
  localStorage.setItem(DB_KEYS.SUBMISSIONS, JSON.stringify(current));
  updateUserCategory(submission.userId);
};

const updateUserCategory = (userId: string) => {
  const users = getUsers();
  const subs = getSubmissions().filter(s => s.userId === userId && s.status === SubmissionStatus.COMPLETED);
  const totalMarks = subs.reduce((sum, s) => sum + s.marks, 0);
  const percentage = (totalMarks / 50) * 100;

  const userIndex = users.findIndex(u => u.id === userId);
  if (userIndex > -1) {
    if (percentage >= 80) users[userIndex].category = PerformanceCategory.EXCELLENT;
    else if (percentage >= 40) users[userIndex].category = PerformanceCategory.GOOD;
    else users[userIndex].category = PerformanceCategory.MODERATE;
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(users));

    const currentUser = getCurrentUser();
    if (currentUser && currentUser.id === userId) {
      localStorage.setItem(DB_KEYS.CURRENT_USER, JSON.stringify(users[userIndex]));
    }
  }
};

export const getCurrentUser = (): User | null => {
  const user = localStorage.getItem(DB_KEYS.CURRENT_USER);
  return user ? JSON.parse(user) : null;
};

export const login = (email: string): User | null => {
  const users = getUsers();
  const user = users.find(u => u.email === email);
  if (user) {
    localStorage.setItem(DB_KEYS.CURRENT_USER, JSON.stringify(user));
    return user;
  }
  return null;
};

export const logout = () => {
  localStorage.removeItem(DB_KEYS.CURRENT_USER);
};

