  const [loading, setLoading] = useState(true);

  useEffect(() => {
    initDb();
    const currentUser = getCurrentUser();
    if (currentUser) setUser(currentUser);
    setLoading(false);
  }, []);

  const handleLogin = () => setUser(getCurrentUser());
  const handleLogout = () => { logout(); setUser(null); };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-slate-50"><div className="animate-spin h-10 w-10 border-4 border-indigo-600 border-t-transparent rounded-full"></div></div>;

  if (!user) return <LoginView onLogin={handleLogin} />;

  return (
