// --- LOGIN VIEW ---
const LoginView: React.FC<{ onLogin: (email: string) => void }> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError('');

    setTimeout(() => {
      const user = login(email);
      if (user) {
        if (user.role === UserRole.USER) {
          const canAccess = incrementAccess(user.id);
          if (!canAccess) {
             setError(`Daily limit reached (${APP_CONFIG.MAX_DAILY_ACCESS}/3 logins). Please return tomorrow.`);
             setIsSubmitting(false);
             return;
          }
        }
        onLogin(email);
      } else {
        setError('Account not found. Please use a registered @gmail.com account.');
        setIsSubmitting(false);
      }
    }, 800);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] flex flex-col justify-center items-center p-6 relative">
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-50 rounded-full blur-3xl opacity-60"></div>
      <div className="w-full max-w-md relative z-10">
        <div className="bg-white rounded-[2rem] shadow-2xl p-10 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-gradient-to-tr from-indigo-600 to-indigo-400 rounded-3xl flex items-center justify-center shadow-2xl mx-auto mb-6">
              <span className="text-white font-black text-4xl">AI</span>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">SmartDev Tracker</h1>
            <p className="text-slate-500 mt-2 font-medium italic">Empowering your coding journey</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Gmail Address</label>
              <input type="email" required className="w-full px-5 py-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium" placeholder="you@gmail.com" value={email} onChange={(e) => setEmail(e.target.value)} />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Password</label>
              <input type="password" required className="w-full px-5 py-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} />
