            {error && <div className="bg-red-50 text-red-600 text-xs font-bold p-3 rounded-xl border border-red-100">{error}</div>}
            <Button type="submit" fullWidth size="lg" className="py-5 shadow-xl rounded-2xl text-lg" disabled={isSubmitting}>
              {isSubmitting ? 'Sign In Now' : 'Sign In Now'}
