          <div className="mt-6 grid grid-cols-2 gap-3">
            <button onClick={() => {setEmail('admin@gmail.com'); setPassword('password');}} className="p-3 rounded-xl border border-slate-100 hover:bg-slate-50 text-center transition-colors">
              <p className="text-xs font-bold text-indigo-600">Admin Account</p>
