// --- USER DASHBOARD ---
const UserDashboard: React.FC<{ user: User }> = ({ user }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [activeProblem, setActiveProblem] = useState<Problem | null>(null);
  const [encouragement, setEncouragement] = useState<{show: boolean, msg: string, emoji: string}>({show: false, msg: '', emoji: ''});
  const [quote] = useState(() => MOTIVATIONAL_QUOTES[Math.floor(Math.random() * MOTIVATIONAL_QUOTES.length)]);

  useEffect(() => {
    setSubmissions(getSubmissions().filter(s => s.userId === user.id));
  }, [user.id]);

  const stats: DailyStats = {
    totalTasks: APP_CONFIG.DAILY_TASK_COUNT,
    completedTasks: submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length,
    remainingTasks: APP_CONFIG.DAILY_TASK_COUNT - submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length,
    marks: submissions.reduce((sum, s) => sum + s.marks, 0),
    productivity: (submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length / APP_CONFIG.DAILY_TASK_COUNT) * 100
  };

  const handleSolveSubmit = (status: SubmissionStatus, code: string, marks: number) => {
    if (!activeProblem) return;
    const newSub: Submission = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      problemId: activeProblem.id,
      language: 'python',
      status,
      marks,
      code,
      timestamp: new Date().toISOString()
    };
    addSubmission(newSub);
    setSubmissions(prev => {
        const existingIndex = prev.findIndex(s => s.problemId === activeProblem.id);
        if (existingIndex > -1) {
            const updated = [...prev];
            updated[existingIndex] = newSub;
            return updated;
        }
        return [...prev, newSub];
    });
    setActiveProblem(null);

    const nextCompletedCount = stats.completedTasks + 1;
    let msg = "Good!";
    let emoji = "✨";
    if (nextCompletedCount === 2) { msg = "Very Good!"; emoji = "🔥"; }
    else if (nextCompletedCount === 3) { msg = "Excellent!"; emoji = "🌟"; }
    else if (nextCompletedCount === 4) { msg = "Fantablouse!"; emoji = "🚀"; }
    else if (nextCompletedCount === 5) { msg = "Task Complete! Legend!"; emoji = "🏆"; }

    setEncouragement({ show: true, msg, emoji });
    setTimeout(() => setEncouragement(prev => ({ ...prev, show: false })), 3000);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6">
      {encouragement.show && (
        <div className="fixed inset-0 flex items-center justify-center z-[300] pointer-events-none">
          <div className="bg-white/90 backdrop-blur-xl border border-indigo-100 shadow-2xl p-10 rounded-[3rem] text-center animate-bounce-in flex flex-col items-center">
            <span className="text-8xl mb-6">{encouragement.emoji}</span>
            <h3 className="text-4xl font-black text-slate-900 mb-2">{encouragement.msg}</h3>
          </div>
        </div>
      )}

      {/* ACCESS & MOTIVATION HEADER */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-12">
        <div className="lg:col-span-2 space-y-4">
           <div className="flex items-center gap-4">
             <h2 className="text-4xl font-black text-slate-900 tracking-tight">{user.name}</h2>
             <div className="px-4 py-1.5 bg-indigo-50 rounded-full border border-indigo-100 text-indigo-600 font-bold text-xs uppercase tracking-widest">
                Session {user.accessCount}/3 Today
             </div>
           </div>
           <p className="text-slate-500 font-medium text-lg">Your Daily Progression Journey</p>
        </div>
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-500 p-6 rounded-[2rem] text-white shadow-xl relative overflow-hidden">
           <div className="relative z-10 italic font-medium">"{quote}"</div>
           <div className="absolute -bottom-4 -right-4 text-9xl text-white/10 font-serif">“</div>
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
        {[
          { label: 'Progress', value: `${stats.completedTasks}/5`, color: 'bg-white', icon: '🎯' },
          { label: 'Total Score', value: `${stats.marks} pts`, color: 'bg-white', icon: '⚡' },
          { label: 'Efficiency', value: `${stats.productivity}%`, color: 'bg-white', icon: '📈' },
          { label: 'Rank Status', value: user.category, color: 'bg-white', icon: '👑' },
        ].map((item, idx) => (
          <div key={idx} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-center gap-6">
            <div className={`w-12 h-12 rounded-2xl bg-indigo-50 flex items-center justify-center text-xl`}>
              {item.icon}
            </div>
            <div>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{item.label}</p>
              <h4 className="text-xl font-bold text-slate-900">{item.value}</h4>
            </div>
          </div>
        ))}
      </div>

      {/* TASK MODULES - PROGRESSIVE */}
      <div className="space-y-6">
        {PROBLEMS.map((problem, index) => {
          const sub = submissions.find(s => s.problemId === problem.id);
          const isCompleted = sub?.status === SubmissionStatus.COMPLETED;

          return (
            <div key={problem.id} className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden p-2 group hover:shadow-lg transition-all">
               <div className={`p-8 rounded-[1.8rem] flex flex-col md:flex-row items-center gap-8 ${isCompleted ? 'bg-emerald-50/20' : 'bg-white'}`}>
                  <div className={`w-16 h-16 rounded-2xl flex items-center justify-center font-black text-2xl shrink-0 ${isCompleted ? 'bg-emerald-500 text-white' : 'bg-slate-50 text-slate-300'}`}>
                    {index + 1}
                  </div>
                  <div className="flex-1 text-center md:text-left">
                    <div className="flex flex-col md:flex-row md:items-center gap-2 mb-2">
                       <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest">Module: {problem.moduleName}</span>
                       <span className="hidden md:block w-1 h-1 bg-slate-200 rounded-full"></span>
                       <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Level: {problem.level}</span>
                    </div>
                    <h4 className="text-2xl font-bold text-slate-900 mb-1">{problem.title}</h4>
                    <p className="text-sm text-slate-500 font-medium max-w-2xl">{problem.description}</p>
                  </div>
                  <div className="shrink-0 w-full md:w-auto">
                    {isCompleted ? (
                      <div className="flex items-center justify-center gap-2 text-emerald-600 font-bold px-8 py-3 bg-emerald-100/30 rounded-2xl">
                        <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd"></path></svg>
                        Level Complete
                      </div>
                    ) : (
                      <Button size="lg" className="w-full md:w-auto px-12 rounded-2xl font-bold shadow-indigo-100" onClick={() => setActiveProblem(problem)}>Start Module</Button>
                    )}
                  </div>
               </div>
            </div>
          );
        })}
      </div>

      {activeProblem && <CodeEditor problem={activeProblem} onClose={() => setActiveProblem(null)} onSubmit={handleSolveSubmit} />}
    </div>
  );
};

