export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    initDb();
    const currentUser = getCurrentUser();
    if (currentUser) setUser(currentUser);
    setLoading(false);
  }, []);

  const handleLogin = () => setUser(getCurrentUser());
  const handleLogout = () => { logout(); setUser(null); };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-slate-50"><div className="animate-spin h-10 w-10 border-4 border-indigo-600 border-t-transparent rounded-full"></div></div>;

  if (!user) return <LoginView onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20">
      <Navbar user={user} onLogout={handleLogout} />
      <main>{user.role === UserRole.ADMIN ? <AdminDashboard /> : <UserDashboard user={user} />}</main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { User, UserRole, Problem, Submission, SubmissionStatus, DailyStats, PerformanceCategory } from './types';
import { login, logout, getCurrentUser, initDb, getSubmissions, addSubmission, getUsers, incrementAccess } from './services/mockDb';
import { PROBLEMS, APP_CONFIG, MOTIVATIONAL_QUOTES } from './constants';
import { Navbar } from './components/Navbar';
import { Button } from './components/Button';
import { CountdownTimer } from './components/CountdownTimer';
import { CodeEditor } from './components/CodeEditor';

// --- LOGIN VIEW ---
const LoginView: React.FC<{ onLogin: (email: string) => void }> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError('');

    setTimeout(() => {
      const user = login(email);
      if (user) {
        if (user.role === UserRole.USER) {
          const canAccess = incrementAccess(user.id);
          if (!canAccess) {
             setError(`Daily limit reached (${APP_CONFIG.MAX_DAILY_ACCESS}/3 logins). Please return tomorrow.`);
             setIsSubmitting(false);
             return;
          }
        }
        onLogin(email);
      } else {
        setError('Account not found. Please use a registered @gmail.com account.');
        setIsSubmitting(false);
      }
    }, 800);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] flex flex-col justify-center items-center p-6 relative">
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-50 rounded-full blur-3xl opacity-60"></div>
      <div className="w-full max-w-md relative z-10">
        <div className="bg-white rounded-[2rem] shadow-2xl p-10 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-gradient-to-tr from-indigo-600 to-indigo-400 rounded-3xl flex items-center justify-center shadow-2xl mx-auto mb-6">
              <span className="text-white font-black text-4xl">AI</span>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">SmartDev Tracker</h1>
            <p className="text-slate-500 mt-2 font-medium italic">Empowering your coding journey</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-5">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Gmail Address</label>
              <input type="email" required className="w-full px-5 py-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium" placeholder="you@gmail.com" value={email} onChange={(e) => setEmail(e.target.value)} />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Password</label>
              <input type="password" required className="w-full px-5 py-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} />
            </div>
            {error && <div className="bg-red-50 text-red-600 text-xs font-bold p-3 rounded-xl border border-red-100">{error}</div>}
            <Button type="submit" fullWidth size="lg" className="py-5 shadow-xl rounded-2xl text-lg" disabled={isSubmitting}>
              Sign In Now
            </Button>
          </form>

          <div className="mt-6 grid grid-cols-2 gap-3">
            <button onClick={() => {setEmail('admin@gmail.com'); setPassword('password');}} className="p-3 rounded-xl border border-slate-100 hover:bg-slate-50 text-center transition-colors">
              <p className="text-xs font-bold text-indigo-600">Admin Account</p>
            </button>
            <button onClick={() => {setEmail('student1@gmail.com'); setPassword('password');}} className="p-3 rounded-xl border border-slate-100 hover:bg-slate-50 text-center transition-colors">
              <p className="text-xs font-bold text-emerald-600">Student Account</p>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

// --- USER DASHBOARD ---
const UserDashboard: React.FC<{ user: User }> = ({ user }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [activeProblem, setActiveProblem] = useState<Problem | null>(null);
  const [encouragement, setEncouragement] = useState<{show: boolean, msg: string, emoji: string}>({show: false, msg: '', emoji: ''});
  const [emailNotif, setEmailNotif] = useState<{show: boolean}>({show: false});
  const [quote] = useState(() => MOTIVATIONAL_QUOTES[Math.floor(Math.random() * MOTIVATIONAL_QUOTES.length)]);

  useEffect(() => {
    setSubmissions(getSubmissions().filter(s => s.userId === user.id));
  }, [user.id]);

  const stats: DailyStats = {
    totalTasks: APP_CONFIG.DAILY_TASK_COUNT,
    completedTasks: submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length,
    remainingTasks: APP_CONFIG.DAILY_TASK_COUNT - submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length,
    marks: submissions.reduce((sum, s) => sum + s.marks, 0),
    productivity: (submissions.filter(s => s.status === SubmissionStatus.COMPLETED).length / APP_CONFIG.DAILY_TASK_COUNT) * 100
  };

  const handleSolveSubmit = (status: SubmissionStatus, code: string, marks: number) => {
    if (!activeProblem) return;
    const newSub: Submission = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      problemId: activeProblem.id,
      language: 'python',
      status,
      marks,
      code,
      timestamp: new Date().toISOString()
    };
    addSubmission(newSub);
    setSubmissions(prev => {
        const existingIndex = prev.findIndex(s => s.problemId === activeProblem.id);
        if (existingIndex > -1) {
            const updated = [...prev];
            updated[existingIndex] = newSub;
            return updated;
        }
        return [...prev, newSub];
    });
    setActiveProblem(null);

    if (status === SubmissionStatus.COMPLETED) {
      const nextCompletedCount = stats.completedTasks + 1;
      let msg = "Level Up!";
      let emoji = "🚀";
      if (nextCompletedCount === 2) { msg = "Brilliant Mind!"; emoji = "🔥"; }
      else if (nextCompletedCount === 3) { msg = "Code Warrior!"; emoji = "⚔️"; }
      else if (nextCompletedCount === 4) { msg = "Logic Master!"; emoji = "🧠"; }
      else if (nextCompletedCount === 5) { msg = "Ultimate Achiever!"; emoji = "👑"; }

      setEncouragement({ show: true, msg, emoji });
      setEmailNotif({ show: true });

      // Auto-hide effects
      setTimeout(() => setEncouragement(prev => ({ ...prev, show: false })), 3500);
      setTimeout(() => setEmailNotif({ show: false }), 5000);
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6">
      {/* Central Encouragement Overlay */}
      {encouragement.show && (
