const LoginView: React.FC<{ onLogin: (email: string) => void }> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError('');

    setTimeout(() => {
      const user = login(email);
      if (user) {
        if (user.role === UserRole.USER) {
          const canAccess = incrementAccess(user.id);
          if (!canAccess) {
             setError(`Daily limit reached (${APP_CONFIG.MAX_DAILY_ACCESS}/3 logins). Please return tomorrow.`);
             setIsSubmitting(false);
             return;
          }
        }
        onLogin(email);
      } else {
        setError('Account not found. Please use a registered @gmail.com account.');
        setIsSubmitting(false);
      }
    }, 800);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] flex flex-col justify-center items-center p-6 relative overflow-hidden">
      {/* Dynamic Background elements */}
      <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-indigo-100/40 rounded-full blur-[120px] -mr-64 -mt-64 animate-pulse"></div>
