          </form>

          <div className="mt-8 pt-8 border-t border-slate-50 grid grid-cols-2 gap-4">
            <button onClick={() => {setEmail('admin@gmail.com'); setPassword('password');}} className="p-3 rounded-2xl bg-slate-50 hover:bg-slate-100 text-center transition-colors group">
              <p className="text-[10px] font-bold text-slate-400 group-hover:text-indigo-600 uppercase tracking-widest">Admin Demo</p>
            </button>
            <button onClick={() => {setEmail('student1@gmail.com'); setPassword('password');}} className="p-3 rounded-2xl bg-slate-50 hover:bg-slate-100 text-center transition-colors group">
              <p className="text-[10px] font-bold text-slate-400 group-hover:text-emerald-600 uppercase tracking-widest">Student Demo</p>
            </button>
